class Solution:
    def maxConsecutiveAnswers(self, answerKey: str, k: int) -> int:
        T, F = 'T', 'F'
        left = 0
        max_len = 0
        T_count, F_count = 0, 0
        for right in range(len(answerKey)):
            if answerKey[right] == T:
                T_count += 1
            else:
                F_count += 1
            while right - left + 1 - max(T_count, F_count) > k:
                if answerKey[left] == T:
                    T_count -= 1
                else:
                    F_count -= 1
                left += 1
            max_len = max(max_len, right - left + 1)
        return max_len
